# =============================================================================
# Build a unified data frame with normalized runtime (system / linux)
# =============================================================================

benchmarks <- list(BC=bc, BFS=bfs, CC=cc, CC_SV=cc_sv, PR=pr, PR_SPMV=pr_spmv)

graphs <- c("kron27","kron28","kron29","kron30",
            "uni27","uni28","uni29","uni30",
            "twitter","web","road")
policies <- c("ft","il")
pol_lab <- c(ft="First-Touch", il="Interleaved")
systems <- c("linux","mitosis","wasp","hydra")
sys_lab <- c(linux="Linux", mitosis="Mitosis", wasp="WASP", hydra="Hydra")

df_all <- data.frame()

for (bench_name in names(benchmarks)) {
  d <- benchmarks[[bench_name]]
  for (g in graphs) {
    for (pol in policies) {
      linux_key <- paste0("linux_", pol, "_", g)
      linux_mean <- mean(d[[linux_key]])
      for (s in systems) {
        key <- paste0(s, "_", pol, "_", g)
        sys_mean <- mean(d[[key]])
        sys_sd <- sd(d[[key]])
        df_all <- rbind(df_all, data.frame(
          Benchmark = bench_name,
          Graph = g,
          Policy = pol_lab[pol],
          System = sys_lab[s],
          MeanTime = sys_mean,
          SD = sys_sd,
          NormTime = sys_mean / linux_mean,
          stringsAsFactors = FALSE
        ))
      }
    }
  }
}

df_all$System <- factor(df_all$System, levels = c("Linux","Mitosis","WASP","Hydra"))
df_all$Benchmark <- factor(df_all$Benchmark,
                           levels = c("BC","BFS","CC","CC_SV","PR","PR_SPMV"))

# Graph ordering: synthetic small->large, then real
graph_order <- c("kron27","kron28","kron29","kron30",
                 "uni27","uni28","uni29","uni30",
                 "twitter","web","road")
df_all$Graph <- factor(df_all$Graph, levels = graph_order)

sys_colors <- c("Linux" = "#E74C3C", "Mitosis" = "#2ECC71",
                "WASP" = "#3498DB", "Hydra" = "#9B59B6")

# =============================================================================
# PLOT 1: Per-benchmark bar charts of normalized runtime, faceted by policy
# =============================================================================

pdf("bar_per_benchmark.pdf", width = 16, height = 7)

for (bench in levels(df_all$Benchmark)) {
  sub <- df_all[df_all$Benchmark == bench, ]
  
  p <- ggplot(sub, aes(x = Graph, y = NormTime, fill = System)) +
    geom_bar(stat = "identity", position = position_dodge(width = 0.8),
             width = 0.75) +
    geom_hline(yintercept = 1.0, linetype = "dashed", color = "gray40") +
    facet_wrap(~ Policy) +
    scale_fill_manual(values = sys_colors) +
    labs(
      title = paste0("GAP ", bench, " - Normalized Runtime (relative to Linux)"),
      subtitle = "128 threads | n=5 | Dashed line = Linux baseline (1.0) | < 1.0 = faster than Linux",
      x = "Input Graph",
      y = "Runtime / Linux Runtime",
      fill = "System"
    ) +
    theme_minimal(base_size = 13) +
    theme(
      axis.text.x = element_text(angle = 45, hjust = 1, size = 10),
      plot.title = element_text(face = "bold"),
      strip.text = element_text(face = "bold", size = 12),
      legend.position = "top"
    )
  
  print(p)
}

dev.off()
cat("Saved per-benchmark bar charts to bar_per_benchmark.pdf\n")

# =============================================================================
# PLOT 2: Geometric mean speedup summary across all graphs, per benchmark
# =============================================================================

# Compute geometric mean of (linux_time / system_time) per benchmark+policy+system
df_summary <- data.frame()
for (bench_name in names(benchmarks)) {
  d <- benchmarks[[bench_name]]
  for (pol in policies) {
    for (s in systems) {
      norms <- c()
      for (g in graphs) {
        linux_key <- paste0("linux_", pol, "_", g)
        sys_key <- paste0(s, "_", pol, "_", g)
        norms <- c(norms, mean(d[[sys_key]]) / mean(d[[linux_key]]))
      }
      df_summary <- rbind(df_summary, data.frame(
        Benchmark = bench_name,
        Policy = pol_lab[pol],
        System = sys_lab[s],
        MeanNormTime = mean(norms),
        stringsAsFactors = FALSE
      ))
    }
  }
}

df_summary$System <- factor(df_summary$System,
                            levels = c("Linux","Mitosis","WASP","Hydra"))
df_summary$Benchmark <- factor(df_summary$Benchmark,
                               levels = c("BC","BFS","CC","CC_SV","PR","PR_SPMV"))

pdf("bar_mean_normalized.pdf", width = 14, height = 6)

p2 <- ggplot(df_summary, aes(x = Benchmark, y = MeanNormTime, fill = System)) +
  geom_bar(stat = "identity", position = position_dodge(width = 0.8),
           width = 0.75) +
  geom_hline(yintercept = 1.0, linetype = "dashed", color = "gray40") +
  facet_wrap(~ Policy) +
  scale_fill_manual(values = sys_colors) +
  labs(
    title = "Mean Normalized Runtime (across all 11 graphs)",
    subtitle = "128 threads | n=5 | Dashed line = Linux baseline (1.0) | < 1.0 = faster than Linux",
    x = "Benchmark",
    y = "Mean Normalized Runtime (System / Linux)",
    fill = "System"
  ) +
  theme_minimal(base_size = 14) +
  theme(
    plot.title = element_text(face = "bold"),
    strip.text = element_text(face = "bold", size = 13),
    legend.position = "top"
  )

print(p2)

dev.off()
cat("Saved mean normalized runtime bar chart to bar_mean_normalized.pdf\n")

# =============================================================================
# PLOT 3: Heatmap-style – one big overview of all (benchmark x graph) combos
# Group by graph type: Kronecker, Uniform, Real-world
# =============================================================================

# Add graph type column
df_all$GraphType <- ifelse(grepl("kron", df_all$Graph), "Kronecker",
                    ifelse(grepl("uni", df_all$Graph), "Uniform", "Real-World"))
df_all$GraphType <- factor(df_all$GraphType,
                           levels = c("Kronecker","Uniform","Real-World"))

pdf("bar_by_graph_type.pdf", width = 15, height = 10)

for (gtype in levels(df_all$GraphType)) {
  sub <- df_all[df_all$GraphType == gtype, ]
  
  p3 <- ggplot(sub, aes(x = Graph, y = NormTime, fill = System)) +
    geom_bar(stat = "identity", position = position_dodge(width = 0.8),
             width = 0.75) +
    geom_hline(yintercept = 1.0, linetype = "dashed", color = "gray40") +
    facet_grid(Benchmark ~ Policy, scales = "free_y") +
    scale_fill_manual(values = sys_colors) +
    labs(
      title = paste0("All Benchmarks - ", gtype, " Graphs"),
      subtitle = "Normalized to Linux | Dashed = 1.0 (Linux) | < 1.0 = faster",
      x = "Input Graph",
      y = "Runtime / Linux Runtime",
      fill = "System"
    ) +
    theme_minimal(base_size = 12) +
    theme(
      axis.text.x = element_text(angle = 45, hjust = 1),
      plot.title = element_text(face = "bold", size = 15),
      strip.text = element_text(face = "bold"),
      legend.position = "top"
    )
  
  print(p3)
}

dev.off()
cat("Saved graph-type faceted bar charts to bar_by_graph_type.pdf\n")

cat("\n=== All bar diagrams generated ===\n")
cat("  1. bar_per_benchmark.pdf  – One page per benchmark, bars per graph\n")
cat("  2. bar_mean_normalized.pdf - Summary: mean normalized runtime per benchmark\n")
cat("  3. bar_by_graph_type.pdf  – Grouped by Kronecker/Uniform/Real-World\n")
